// SetKeyValue is the resolver for the setKeyValue field.
func (r *mutationResolver) SetKeyValue(ctx context.Context, input model.SetKeyValueInput) (*ent.KeyValue, error) {
	// MutationEventHook captures the mutation automatically.
	dataType, err := r.validator.ValidateDataTypeInput(ctx, true, input.Data, input.DataTypeID, input.DataTypeSlug)
	if err != nil {
		return nil, err
	}

	mixin.PatchDataTypeIdSlugInput(&input, dataType)

	tx, err := gqltx.ForContext(ctx, ent.TxFromContext)
	if err != nil {
		return nil, err
	}

	// setKeyValue upserts on (tenant, user, name). When an entry with this
	// name already exists it is the row this call rewrites, so exclude it
	// from the uniqueness check below — otherwise the entry's own unchanged
	// unique value would be counted as a collision against itself.
	req := request.ForContext(ctx)
	var excludeID *uuid.UUID
	existing, err := tx.KeyValue.Query().
		Where(
			keyvalue.TenantID(req.MutationTenantID()),
			keyvalue.UserID(req.User().ID),
			keyvalue.Name(input.Name),
			keyvalue.DeletedAtIsNil(),
		).
		Only(ctx)
	switch {
	case err == nil:
		excludeID = &existing.ID
	case ent.IsNotFound(err):
		// No existing entry; this upsert inserts a new row.
	default:
		return nil, err
	}

	if err = r.validator.ValidateInputDataUniqueness(ctx, tx, validator.UniquenessValidationParams{
		Input:     input.Data,
		DataType:  dataType,
		TableName: keyvalue.Table,
		FieldName: keyvalue.FieldData,
		DbDriver:  core.Config.DbDriver,
		ExcludeID: excludeID,
	}); err != nil {
		return nil, err
	}

	keyValueID, err := tx.KeyValue.
		Create().
		SetInput(ent.CreateKeyValueInput{
			DataTypeID:   &dataType.ID,
			DataTypeSlug: &dataType.Slug,
			Data:         input.Data,
			Name:         &input.Name,
		}).
		OnConflict(
			sql.ConflictColumns(keyvalue.FieldTenantID, keyvalue.FieldUserID, keyvalue.FieldName),
			sql.ConflictWhere(sql.IsNull(keyvalue.FieldDeletedAt)),
			mixin.HistoryMixinResolveWithNewValues(ctx),
		).
		ID(ctx)
	if err != nil {
		return nil, err
	}

	keyValue, err := tx.KeyValue.Get(ctx, keyValueID)
	if err != nil {
		return nil, err
	}

	return keyValue, nil
}

