// CheckInUserDevice is the resolver for the checkInUserDevice field.
func (r *mutationResolver) CheckInUserDevice(ctx context.Context, input model.CheckInUserDeviceInput) (*model.CheckInUserDeviceOutput, error) {
	// MutationEventHook captures the mutation automatically.
	tx, err := gqltx.ForContext(ctx, ent.TxFromContext)
	if err != nil {
		return nil, err
	}

	req := request.ForContext(ctx)

	if _, err := tx.Device.Get(ctx, input.DeviceID); err != nil {
		return nil, fmt.Errorf("invalid device: %w", err)
	}

	// Verify that the device is associated with a location
	hasLocation, err := tx.DeviceLocation.
		Query().
		Where(devicelocation.DeviceIDEQ(input.DeviceID)).
		Exist(ctx)
	if err != nil {
		return nil, err
	}
	if !hasLocation {
		return nil, model.ErrDeviceUnassociated
	}

	// Verify that no other user is currently checked in on this device
	existingCheckIn, err := tx.DeviceUser.
		Query().
		Where(deviceuser.DeviceIDEQ(input.DeviceID)).
		First(ctx)
	if err != nil && !ent.IsNotFound(err) {
		return nil, err
	}
	if existingCheckIn != nil {
		return nil, model.ErrDeviceInUse
	}

	deviceUser, err := tx.DeviceUser.
		Create().
		SetDeviceID(input.DeviceID).
		SetUserID(req.User().ID).
		Save(ctx)
	if err != nil {
		return nil, err
	}

	return &model.CheckInUserDeviceOutput{DeviceUser: deviceUser}, nil
}

// CheckOutUserDevice is the resolver for the checkOutUserDevice field.
func (r *mutationResolver) CheckOutUserDevice(ctx context.Context, input model.CheckOutUserDeviceInput) (*model.CheckOutUserDeviceOutput, error) {
	// MutationEventHook captures the mutation automatically.
	tx, err := gqltx.ForContext(ctx, ent.TxFromContext)
	if err != nil {
		return nil, err
	}

	req := request.ForContext(ctx)
	var resp model.CheckOutUserDeviceOutput

	if _, err := tx.Device.Get(ctx, input.DeviceID); err != nil {
		return nil, fmt.Errorf("invalid device: %w", err)
	}

	deviceUsers, err := tx.DeviceUser.
		Query().
		Where(
			deviceuser.DeviceIDEQ(input.DeviceID),
			deviceuser.UserIDEQ(req.User().ID),
		).
		AllPages(ctx, mixin.Limit)
	if err != nil {
		return nil, err
	}

	if len(deviceUsers) == 0 {
		return &resp, nil
	}

	resp.DeviceUser = deviceUsers

	for _, v := range deviceUsers {
		_, err := tx.DeviceUser.
			UpdateOneID(v.ID).
			SetDeletedAt(time.Now().UTC()).
			SetDeletedBy(req.User().ID).
			Save(ctx)
		if err != nil {
			return nil, err
		}
	}

	return &resp, nil
}

// PatchLocationData applies RFC 6902 JSON Patch operations to the location's data field.
// MutationEventHook captures field-level changes automatically.
func (r *mutationResolver) PatchLocationData(ctx context.Context, id uuid.UUID, patches []*jsonpatch.JSONPatchInput) (*model.LocationOutput, error) {
	tx, err := gqltx.ForContext(ctx, ent.TxFromContext)
	if err != nil {
		return nil, err
	}

	q := tx.Location.Query().Where(location.IDEQ(id))
	if core.Config.DbDriver == dialect.Postgres {
		q = q.ForUpdate()
	}
	entity, err := q.Only(ctx)
	if err != nil {
		return nil, err
	}

	patched, err := jsonpatch.PatchEntityData(ctx, jsonpatch.PatchParams{
		CurrentData:  entity.Data,
		DataTypeID:   &entity.DataTypeID,
		DataTypeSlug: &entity.DataTypeSlug,
		Patches:      jsonpatch.ToOperations(patches),
		Validator:    r.validator,
		Executor:     tx,
		TableName:    location.Table,
		FieldName:    location.FieldData,
		DbDriver:     core.Config.DbDriver,
		EntityID:     id,
	})
	if err != nil {
		return nil, err
	}

	updated, err := tx.Location.UpdateOneID(id).SetData(patched).Save(ctx)
	if err != nil {
		return nil, err
	}

	return &model.LocationOutput{Location: updated}, nil
}

